package com.taskflow.repository;

import com.taskflow.entity.User;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.orm.jpa.DataJpaTest;
import org.springframework.boot.test.autoconfigure.orm.jpa.TestEntityManager;

import java.util.Optional;

import static org.junit.jupiter.api.Assertions.*;

@DataJpaTest
class UserRepositoryTest {

    @Autowired
    private TestEntityManager entityManager;

    @Autowired
    private UserRepository userRepository;

    private User createAndPersistUser(String username, String displayName) {
        User user = new User();
        user.setUsername(username);
        user.setPassword("$2a$10$hashedpassword");
        user.setDisplayName(displayName);
        entityManager.persistAndFlush(user);
        return user;
    }

    @Test
    void shouldFindUserByUsername() {
        User saved = createAndPersistUser("testuser", "Test User");

        Optional<User> found = userRepository.findByUsername("testuser");

        assertTrue(found.isPresent());
        assertEquals(saved.getId(), found.get().getId());
        assertEquals("testuser", found.get().getUsername());
        assertEquals("Test User", found.get().getDisplayName());
    }

    @Test
    void shouldReturnEmptyWhenUsernameNotFound() {
        Optional<User> found = userRepository.findByUsername("nonexistent");

        assertFalse(found.isPresent());
    }

    @Test
    void shouldAutoGenerateId() {
        User saved = createAndPersistUser("testuser", "Test User");

        assertNotNull(saved.getId());
    }

    @Test
    void shouldEnforceUniqueUsername() {
        createAndPersistUser("testuser", "User 1");

        User duplicate = new User();
        duplicate.setUsername("testuser");
        duplicate.setPassword("$2a$10$anotherHash");
        duplicate.setDisplayName("User 2");

        assertThrows(Exception.class, () -> {
            entityManager.persistAndFlush(duplicate);
        });
    }

    // M1-AC3: bcrypt stored - verify password field stores hash, not plain text
    @Test
    void shouldStoreBcryptHashNotPlaintext() {
        String bcryptHash = "$2a$10$N9qo8uLOickgx2ZMRZoMyeIjZAgcfl7p92ldGxad68LJZdL17lhWy";
        User user = new User();
        user.setUsername("hashuser");
        user.setPassword(bcryptHash);
        user.setDisplayName("Hash User");
        entityManager.persistAndFlush(user);

        User found = entityManager.find(User.class, user.getId());
        assertEquals(bcryptHash, found.getPassword(), "Password should be stored as bcrypt hash");
        assertNotEquals("plainpassword", found.getPassword());
    }

    @Test
    void shouldSetCreatedAtAutomatically() {
        User saved = createAndPersistUser("timeuser", "Time User");

        assertNotNull(saved.getCreatedAt(), "createdAt should be set automatically");
    }
}

