import java.util.Collections;
import java.util.List;

import static org.junit.jupiter.api.Assertions.*;

class TaskPageResponseTest {

    @Test
    void shouldGetAndSetAllFields() {
        TaskPageResponse pageResponse = new TaskPageResponse();

        TaskResponse item1 = createTaskResponse(1L, "Task 1");
        TaskResponse item2 = createTaskResponse(2L, "Task 2");
        List<TaskResponse> content = Arrays.asList(item1, item2);

        pageResponse.setContent(content);
        pageResponse.setPage(0);
        pageResponse.setSize(20);
        pageResponse.setTotalElements(50L);
        pageResponse.setTotalPages(3);

        assertEquals(2, pageResponse.getContent().size());
        assertEquals(0, pageResponse.getPage());
        assertEquals(20, pageResponse.getSize());
        assertEquals(50L, pageResponse.getTotalElements());
        assertEquals(3, pageResponse.getTotalPages());
    }

    @Test
    void shouldHandleEmptyContent() {
        TaskPageResponse pageResponse = new TaskPageResponse();
        pageResponse.setContent(Collections.emptyList());
        pageResponse.setPage(0);
        pageResponse.setSize(20);
        pageResponse.setTotalElements(0L);
        pageResponse.setTotalPages(0);

        assertTrue(pageResponse.getContent().isEmpty());
        assertEquals(0L, pageResponse.getTotalElements());
        assertEquals(0, pageResponse.getTotalPages());
    }

    @Test
    void shouldMatchContractStructure() {
        // CONTRACT: TaskPageResponse fields = content:TaskResponse[], page:int, size:int, totalElements:long, totalPages:int
        TaskPageResponse pageResponse = new TaskPageResponse();

        List<TaskResponse> content = Arrays.asList(
                createTaskResponse(1L, "First"),
                createTaskResponse(2L, "Second")
        );

        pageResponse.setContent(content);
        pageResponse.setPage(2);
        pageResponse.setSize(10);
        pageResponse.setTotalElements(25L);
        pageResponse.setTotalPages(3);

        // Verify all contract fields are present and correctly typed
        assertInstanceOf(List.class, pageResponse.getContent());
        assertEquals(2, pageResponse.getPage());
        assertEquals(10, pageResponse.getSize());
        assertEquals(25L, pageResponse.getTotalElements());
        assertEquals(3, pageResponse.getTotalPages());
    }

    private TaskResponse createTaskResponse(Long id, String title) {
        TaskResponse response = new TaskResponse();
        response.setId(id);
        response.setTitle(title);
        response.setPriority(Task.Priority.MEDIUM);
        response.setStatus(Task.TaskStatus.TODO);
        response.setCreatedBy(1L);
        response.setCreatedAt(LocalDateTime.now());
        return response;
    }
}

